## `minigit` (main implementation in Go)

```go
// File: minigit
package main

import (
    "crypto/sha1"
    "encoding/hex"
    "encoding/json"
    "fmt"
    "io"
    "io/ioutil"
    "os"
    "path/filepath"
    "strings"
    "time"
)

const (
    minigitDir   = ".minigit"
    objectsDir   = ".minigit/objects"
    commitsFile  = ".minigit/commits.json"
    indexFile    = ".minigit/index"
)

type Commit struct {
    Hash      string   `json:"hash"`
    Message   string   `json:"message"`
    Timestamp string   `json:"timestamp"`
    Files     []string `json:"files"`
    Parent    string   `json:"parent"`
}

func fatal(format string, args ...interface{}) {
    fmt.Fprintf(os.Stderr, "minigit: "+format+"\n", args...)
    os.Exit(1)
}

func ensureRepo() {
    if _, err := os.Stat(minigitDir); os.IsNotExist(err) {
        fatal("not a minigit repository (or any of the parent directories): .minigit")
    }
}

func cmdInit() {
    os.Mkdir(minigitDir, 0755)
    os.Mkdir(objectsDir, 0755)
    ioutil.WriteFile(commitsFile, []byte("[]"), 0644)
    ioutil.WriteFile(indexFile, []byte(""), 0644)
    fmt.Println("Initialized empty minigit repository in .minigit")
}

func readIndex() ([]string, error) {
    data, err := ioutil.ReadFile(indexFile)
    if err != nil {
        return []string{}, nil // empty index
    }
    files := strings.Split(strings.TrimSpace(string(data)), "\n")
    var res []string
    for _, f := range files {
        if f != "" {
            res = append(res, f)
        }
    }
    return res, nil
}

func writeIndex(files []string) {
    data := strings.Join(files, "\n")
    ioutil.WriteFile(indexFile, []byte(data), 0644)
}

func cmdAdd(args []string) {
    ensureRepo()
    if len(args) == 0 {
        fatal("add: missing file operand")
    }
    files, _ := readIndex()
    fileSet := make(map[string]bool)
    for _, f := range files {
        fileSet[f] = true
    }
    for _, f := range args {
        // Check if file exists
        st, err := os.Stat(f)
        if err != nil || st.IsDir() {
            fatal("add: '%s' does not exist or is a directory", f)
        }
        if !fileSet[f] {
            files = append(files, f)
        }
        // Stage file by copying into objects store (by hash of content)
        content, _ := ioutil.ReadFile(f)
        hash := sha1sum(content)
        objPath := filepath.Join(objectsDir, hash)
        ioutil.WriteFile(objPath, content, 0644)
    }
    writeIndex(files)
}

func sha1sum(content []byte) string {
    h := sha1.New()
    h.Write(content)
    return hex.EncodeToString(h.Sum(nil))
}

func readCommits() []Commit {
    data, err := ioutil.ReadFile(commitsFile)
    if err != nil {
        return []Commit{}
    }
    var res []Commit
    _ = json.Unmarshal(data, &res)
    return res
}

func writeCommits(commits []Commit) {
    data, _ := json.MarshalIndent(commits, "", "  ")
    ioutil.WriteFile(commitsFile, data, 0644)
}

func cmdCommit(args []string) {
    ensureRepo()
    if len(args) < 2 || args[0] != "-m" {
        fatal("commit: usage: commit -m <msg>")
    }
    msg := args[1]
    files, _ := readIndex()
    if len(files) == 0 {
        fatal("nothing to commit")
    }
    commits := readCommits()
    // Generate a hash, for simplicity, use time+msg+files
    content := []byte(strings.Join(files, ",") + msg + time.Now().String())
    hash := sha1sum(content)[:8]
    var parent string
    if len(commits) > 0 {
        parent = commits[len(commits)-1].Hash
    } else {
        parent = ""
    }
    commit := Commit{
        Hash:      hash,
        Message:   msg,
        Timestamp: time.Now().Format("2006-01-02 15:04:05"),
        Files:     files,
        Parent:    parent,
    }
    commits = append(commits, commit)
    writeCommits(commits)
    // Clear index
    writeIndex([]string{})
    fmt.Printf("[%s] %s\n", hash, msg)
}

func cmdLog() {
    ensureRepo()
    commits := readCommits()
    for i := len(commits) - 1; i >= 0; i-- {
        c := commits[i]
        fmt.Printf("commit %s\n", c.Hash)
        fmt.Printf("    %s\n", c.Message)
    }
}

func readWorkDirFiles() []string {
    var files []string
    entries, _ := ioutil.ReadDir(".")
    for _, ent := range entries {
        if ent.IsDir() || ent.Name() == minigitDir {
            continue
        }
        files = append(files, ent.Name())
    }
    return files
}

func cmdStatus() {
    ensureRepo()
    cwdFiles := readWorkDirFiles()
    index, _ := readIndex()
    commits := readCommits()
    tracked := make(map[string]bool)
    if len(commits) > 0 {
        for _, f := range commits[len(commits)-1].Files {
            tracked[f] = true
        }
    }
    indexSet := make(map[string]bool)
    for _, f := range index {
        indexSet[f] = true
    }
    // Staged files
    for _, f := range index {
        fmt.Printf("staged: %s\n", f)
    }
    // Modified or untracked files
    for _, f := range cwdFiles {
        if tracked[f] {
            // check if modified
            content, _ := ioutil.ReadFile(f)
            hash := sha1sum(content)
            objPath := filepath.Join(objectsDir, hash)
            if _, err := os.Stat(objPath); os.IsNotExist(err) && !indexSet[f] {
                fmt.Printf("modified: %s\n", f)
            }
        } else if !indexSet[f] {
            fmt.Printf("untracked: %s\n", f)
        }
    }
}

func main() {
    if len(os.Args) < 2 {
        fmt.Println("minigit: usage: minigit <command> ...")
        os.Exit(1)
    }
    cmd := os.Args[1]
    args := os.Args[2:]
    switch cmd {
    case "init":
        cmdInit()
    case "add":
        cmdAdd(args)
    case "commit":
        cmdCommit(args)
    case "log":
        cmdLog()
    case "status":
        cmdStatus()
    default:
        fmt.Println("minigit: unknown command:", cmd)
        os.Exit(1)
    }
}
```

